[Fact]
public void ShouldAlignColumnsCorrectlyWithFullWidthUnicodeCharacters()
{
    // Arrange
    // '田中さん' consists of 4 characters, but each has a visual width of 2 (Total visual width = 8)
    // 'Name' has a length and visual width of 4.
    // 'Alice' has a length and visual width of 5.
    // The longest entry in the first column is '田中さん' (8).
    var table = new ConsoleTable("Name", "Age")
        .AddRow("Alice", 25)
        .AddRow("田中さん", 30);

    // Act
    var output = table.ToString();

    // Assert
    // Column 1 width = 8. Column 2 width = 3 (from "Age").
    // Total line width calculation: 2 (left border) + 8 (Col1) + 3 (middle border) + 3 (Col2) + 2 (right border) = 18 dashes.
    // Padding for 'Name': 8 - 4 = 4 spaces.
    // Padding for 'Alice': 8 - 5 = 3 spaces.
    // Padding for '田中さん': 8 - 8 = 0 spaces.
    var expected = 
        """
          ------------------ 
          | Name     | Age |
          ------------------ 
          | Alice    | 25  |
          ------------------ 
          | 田中さん | 30  |
          ------------------ 

          Count: 2
         """.Replace("\r\n", "\n");

    Assert.Equal(expected, output.Replace("\r\n", "\n"));
}
